from collections import Counter

class Solution:
    def minWindow(self, s: str, t: str) -> str:
        if not t or not s:
            return ""
        t_count = Counter(t)
        required = len(t_count)
        formed = 0
        window = {}
        l = 0
        ans = (float('inf'), 0, 0)  # (length, left, right)
        for r in range(len(s)):
            char = s[r]
            window[char] = window.get(char, 0) + 1
            if char in t_count and window[char] == t_count[char]:
                formed += 1
            while formed == required:
                if r - l + 1 < ans[0]:
                    ans = (r - l + 1, l, r)
                left_char = s[l]
                window[left_char] -= 1
                if left_char in t_count and window[left_char] < t_count[left_char]:
                    formed -= 1
                l += 1
        return "" if ans[0] == float('inf') else s[ans[1]:ans[2] + 1]

# Test cases
sol = Solution()
print(sol.minWindow("ADOBECODEBANC", "ABC"))  # Expected: "BANC"
print(sol.minWindow("a", "a"))                 # Expected: "a"
print(sol.minWindow("a", "aa"))                # Expected: ""

from collections import Counter

class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        if len(s1) > len(s2):
            return False
        s1_count = Counter(s1)
        window = Counter(s2[:len(s1)])
        if window == s1_count:
            return True
        for i in range(len(s1), len(s2)):
            window[s2[i]] += 1
            left_char = s2[i - len(s1)]
            window[left_char] -= 1
            if window[left_char] == 0:
                del window[left_char]
            if window == s1_count:
                return True
        return False

