print(sol.search([1], 0))                       # -1

class Solution:
    def searchMatrix(self, matrix, target):
        rows, cols = len(matrix), len(matrix[0])
        l, r = 0, rows * cols - 1
        while l <= r:
            m = (l + r) // 2
            val = matrix[m // cols][m % cols]
            if val == target:
                return True
            elif val < target:
                l = m + 1
            else:
                r = m - 1
        return False


