import heapq

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def build(arr):
    dummy = ListNode(0)
    cur = dummy
    for v in arr:
        cur.next = ListNode(v)
        cur = cur.next
    return dummy.next

def show(head):
    res = []
    while head:
        res.append(head.val)
        head = head.next
    return res

class Solution:
    def mergeKLists(self, lists):
        dummy = ListNode(0)
        cur = dummy
        heap = []
        for i, l in enumerate(lists):
            if l:
                heapq.heappush(heap, (l.val, i, l))
        while heap:
            val, i, node = heapq.heappop(heap)
            cur.next = node
            cur = cur.next
            if node.next:
                heapq.heappush(heap, (node.next.val, i, node.next))
        return dummy.next


sol = Solution()
print(show(sol.mergeKLists([build([1,4,5]), build([1,3,4]), build([2,6])])))   # [1, 1, 2, 3, 4, 4, 5, 6]
print(show(sol.mergeKLists([])))                                                # []
print(show(sol.mergeKLists([build([])])))                                       # []

