class Solution:
    def findItinerary(self, tickets):
        adj = {}
        for src, dst in sorted(tickets):
            if src not in adj:
                adj[src] = []
            adj[src].append(dst)
        result = []

        def dfs(airport):
            while adj.get(airport, []):
                next_dest = adj[airport].pop(0)
                dfs(next_dest)
            result.append(airport)

        dfs("JFK")
        return result[::-1]


