class Solution:
    def rob(self, nums: List[int]) -> int:
        if len(nums) == 1:
            return nums[0]

        def rob_linear(houses):
            a, b = 0, 0
            for num in houses:
                a, b = b, max(b, a + num)
            return b

        return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))


