class Solution:
    def canPartition(self, nums: List[int]) -> bool:
        total = sum(nums)
        if total % 2:
            return False
        target = total // 2
        dp = set([0])
        for num in nums:
            dp = dp | {t + num for t in dp if t + num <= target}
            if target in dp:
                return True
        return target in dp


